function solve(n: number, edges: number[][]): number {
    if (n === 1) {
        return 0;
    }

    const adj: [number, number, number][][] = new Array(n);
    for (let i = 0; i < n; i++) {
        adj[i] = [];
    }

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const s = edge[2];
        const e = edge[3];
        adj[u].push([v, s, e]);
    }

    const dist: number[] = new Array(n).fill(Number.MAX_SAFE_INTEGER);
    dist[0] = 0;

    class MinHeap {
        heap: [number, number][];

        constructor() {
            this.heap = [];
        }

        push(val: [number, number]): void {
            this.heap.push(val);
            this.bubbleUp(this.heap.length - 1);
        }

        pop(): [number, number] | undefined {
            if (this.heap.length === 0) return undefined;
            const min = this.heap[0];
            const last = this.heap.pop()!;
            if (this.heap.length > 0) {
                this.heap[0] = last;
                this.bubbleDown(0);
            }
            return min;
        }

        size(): number {
            return this.heap.length;
        }

        private bubbleUp(idx: number): void {
            if (this.heap.length <= 1) return;
            const element = this.heap[idx];
            const time = element[0];
            while (idx > 0) {
                const parentIdx = Math.floor((idx - 1) / 2);
                if (this.heap[parentIdx][0] <= time) break;
                this.heap[idx] = this.heap[parentIdx];
                idx = parentIdx;
            }
            this.heap[idx] = element;
        }

        private bubbleDown(idx: number): void {
            const element = this.heap[idx];
            const length = this.heap.length;
            while (true) {
                let leftChildIdx = 2 * idx + 1;
                let rightChildIdx = 2 * idx + 2;
                let smallest = idx;

                if (leftChildIdx < length && this.heap[leftChildIdx][0] < this.heap[smallest][0]) {
                    smallest = leftChildIdx;
                }
                if (rightChildIdx < length && this.heap[rightChildIdx][0] < this.heap[smallest][0]) {
                    smallest = rightChildIdx;
                }

                if (smallest === idx) break;
                this.heap[idx] = this.heap[smallest];
                idx = smallest;
            }
            this.heap[idx] = element;
        }
    }

    const heap = new MinHeap();
    heap.push([0, 0]);

    while (heap.size() > 0) {
        const state = heap.pop();
        if (!state) continue;
        const [t, u] = state;

        if (t > dist[u]) {
            continue;
        }

        if (u === n - 1) {
            return t;
        }

        for (const edge of adj[u]) {
            const [v, s, e] = edge;
            if (t > e) {
                continue;
            }

            const candidate = Math.max(t, s) + 1;
            if (candidate < dist[v]) {
                dist[v] = candidate;
                heap.push([candidate, v]);
            }
        }
    }

    return -1;
}
