                idx = smallest;
            }
        }

        isEmpty(): boolean {
            return this.heap.length === 0;
        }
    }

    const heap = new MinHeap();
    heap.push(0, 0);

    while (!heap.isEmpty()) {
        const [time, node] = heap.pop();
        if (time !== dist[node]) continue;
        if (node === n - 1) {
