    if (n === 1) {
        return 0;
    }

    const graph: [number, number, number][][] = Array.from({ length: n }, () => []);
    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const s = edge[2];
        const e = edge[3];
        graph[u].push([v, s, e]);
    }

    const dist: number[] = Array(n).fill(Number.MAX_SAFE_INTEGER);
    dist[0] = 0;

    class MinHeap {
        data: { time: number, node: number }[];
        constructor() {
            this.data = [];
        }
        push(time: number, node: number): void {
            this.data.push({ time, node });
            this.bubbleUp(this.data.length - 1);
        }
        pop(): { time: number, node: number } | undefined {
            if (this.data.length === 0) {
                return undefined;
            }
            const top = this.data[0];
            const last = this.data.pop();
            if (this.data.length > 0 && last !== undefined) {
                this.data[0] = last;
                this.sinkDown(0);
            }
            return top;
        }
        isEmpty(): boolean {
            return this.data.length === 0;
        }
        bubbleUp(index: number): void {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.data[parentIndex].time > this.data[index].time) {
                    [this.data[parentIndex], this.data[index]] = [this.data[index], this.data[parentIndex]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }
        sinkDown(index: number): void {
            const size = this.data.length;
            let current = index;
            while (true) {
                let smallest = current;
                const left = 2 * current + 1;
                const right = 2 * current + 2;
                if (left < size && this.data[left].time < this.data[smallest].time) {
                    smallest = left;
                }
                if (right < size && this.data[right].time < this.data[smallest].time) {
                    smallest = right;
                }
                if (smallest !== current) {
                    [this.data[smallest], this.data[current]] = [this.data[current], this.data[smallest]];
                    current = smallest;
                } else {
                    break;
                }
            }
        }
    }

    const heap = new MinHeap();
    heap.push(0, 0);

    while (!heap.isEmpty()) {
        const state = heap.pop();
        if (state === undefined) continue;
        const time = state.time;
        const node = state.node;

        if (node === n - 1) {
            return time;
        }

        if (time > dist[node]) {
            continue;
        }

        for (const [v, s, e] of graph[node]) {
            const t_leave = Math.max(time, s);
            if (t_leave <= e) {
                const newTime = t_leave + 1;
                if (newTime < dist[v]) {
                    dist[v] = newTime;
                    heap.push(newTime, v);
                }
            }
        }
    }

    return -1;
}
